```cpp
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0);
    uint32_t N = x_shape->GetDim(0);
    uint32_t H_in = x_shape->GetDim(2);
    uint32_t W_in = x_shape->GetDim(3);
    // Get attrs
    auto attrs = context->GetAttrs();
    int64_t out_channels = attrs->GetAttrPointer<int64_t>(1)[0];
    int64_t kernelH = attrs->GetAttrPointer<int64_t>(2)[0];
    int64_t kernelW = attrs->GetAttrPointer<int64_t>(2)[1];
    int64_t stride = attrs->GetAttrPointer<int64_t>(3)[0];
    int64_t padH = attrs->GetAttrPointer<int64_t>(4)[0];
    int64_t padW = attrs->GetAttrPointer<int64_t>(4)[1];
    int64_t dilationH = attrs->GetAttrPointer<int64_t>(5)[0];
    int64_t dilationW = attrs->GetAttrPointer<int64_t>(5)[1];
    int64_t poolKernelH = attrs->GetAttrPointer<int64_t>(6)[0];
    int64_t poolKernelW = attrs->GetAttrPointer<int64_t>(6)[1];
    int64_t poolStride = attrs->GetAttrPointer<int64_t>(7)[0];
    int64_t poolPadH = attrs->GetAttrPointer<int64_t>(8)[0];
    int64_t poolPadW = attrs->GetAttrPointer<int64_t>(8)[1];
    uint32_t H_out = (H_in + 2 * padH - dilationH * (kernelH - 1) - 1) / stride + 1;
    uint32_t W_out = (W_in + 2 * padW - dilationW * (kernelW - 1) - 1) / stride + 1;
    uint32_t poolH_out = (H_out + 2 * poolPadH - poolKernelH) / poolStride + 1;
    uint32_t poolW_out = (W_out + 2 * poolPadW - poolKernelW) / poolStride + 1;
    gert::Shape y_shape({N, (uint32_t)out_channels, poolH_out, poolW_out});
    context->SetOutputShape(0, y_shape);
    return GRAPH_SUCCESS;
}
```

